const overview = $('GA4 Overview Metrics').first().json;
const channels = $('GA4 Channel Breakdown').first().json;
const keywords = $('Search Console Top Keywords').first().json;

// Parse overview metrics
const rows = overview.rows || [];
const thisWeek = rows[0]?.metricValues?.map(m => m.value) || [];
const lastWeek = rows[1]?.metricValues?.map(m => m.value) || [];

const metrics = [
  'Active Users', 'Sessions', 'Pageviews', 
  'Avg Duration (s)', 'Bounce Rate', 'Conversions', 'Revenue'
];

// Calculate changes
const formatChange = (curr, prev) => {
  const c = parseFloat(curr) || 0;
  const p = parseFloat(prev) || 0;
  if (p === 0) return '+N/A';
  const change = ((c - p) / p * 100).toFixed(1);
  return change >= 0 ? `+${change}%` : `${change}%`;
};

// Build overview section
let overviewText = metrics.map((name, i) => {
  const curr = thisWeek[i] || '0';
  const prev = lastWeek[i] || '0';
  const change = formatChange(curr, prev);
  let displayVal = curr;
  if (name === 'Revenue') displayVal = `¥${parseInt(curr).toLocaleString()}`;
  if (name === 'Bounce Rate') displayVal = `${(parseFloat(curr) * 100).toFixed(1)}%`;
  if (name === 'Avg Duration (s)') displayVal = `${Math.round(parseFloat(curr))}s`;
  return `  ${name}: ${displayVal} (${change} WoW)`;
}).join('\n');

// Build channel section
const channelRows = channels.rows || [];
let channelText = channelRows.map(row => {
  const channel = row.dimensionValues[0].value;
  const sessions = parseInt(row.metricValues[0].value).toLocaleString();
  const conversions = row.metricValues[1].value;
  const revenue = `¥${parseInt(row.metricValues[2].value).toLocaleString()}`;
  return `  ${channel}: ${sessions} sessions, ${conversions} conv, ${revenue}`;
}).join('\n');

// Build keyword section
const keywordRows = keywords.rows || [];
let keywordText = keywordRows.slice(0, 10).map((row, i) => {
  const query = row.keys[0];
  const clicks = row.clicks;
  const impressions = row.impressions;
  const position = row.position.toFixed(1);
  return `  ${i + 1}. "${query}" — ${clicks} clicks, ${impressions} imp, pos ${position}`;
}).join('\n');

const report = `[info][title]Weekly Analytics Report (${$now.minus(7, 'days').format('MM/dd')} - ${$now.minus(1, 'days').format('MM/dd')})[/title]` +
`\n■ Overview\n${overviewText}` +
`\n\n■ Traffic by Channel\n${channelText}` +
`\n\n■ Top 10 Search Keywords\n${keywordText}` +
`\n\nReport generated: ${$now.format('yyyy-MM-dd HH:mm')} JST[/info]`;

return [{ json: { report } }];
